vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


float z = q30;
float d = q31;
float pi = q28;
float pi2inv = q29;
float mask_apex = q32;
float zoom = q27;

vec2 c = zoom*(vUv-0.5)*uAspect.xy;

float camera_apex = atan( length(c),z);

bool mask = mask_apex >= camera_apex;

float longitude = atan(c.x,c.y);
float latitude = (pi - camera_apex + asin(d*sin(camera_apex)));

vec2 polar = vec2(longitude,latitude);

vec3 p = vec3( sin(polar.x)*sin(polar.y),cos(polar.x)*sin(polar.y),cos(polar.y));

factorA = p.zy;
factorB = vec2(q20,q21);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zy = product.xy;

factorA = p.zx;
factorB = vec2(q22,q23);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zx = product.xy;

factorA = p.yx;
factorB = vec2(q24,q25);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
p.yx = product.xy;
polar = vec2(atan(p.z,p.x),atan(p.y,length(p.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);

polar = polar;

    vec3 pos = vec3(polar,uTime*0.15);
    vec3 rc = texture3D(sampler_noisevol_hq, pos);
    rc += texture3D(sampler_noisevol_hq, 2*pos)*0.5;
    rc += texture3D(sampler_noisevol_hq, 4*pos)*0.25;
    rc += texture3D(sampler_noisevol_hq, 8*pos)*0.125;
    rc += texture3D(sampler_noisevol_hq, 16*pos)*0.0625;
    //rc = rc*0.556;
    rc = (rc*rc*rc)*2;
    //rc -= GetBlur1(vUv);
    rc *= q3*0.5;

    vec2 ruv = vUv = 0.5 + (vUv-0.5)*(1+(rc.x*.0));
    ret = texture(sampler_fc_main, vec2(ruv.x, ruv.y)).xyz;

    vec3 noise2 = texture(sampler_noise_lq, vUvOriginal*uTexSize.xy*texsize_noise_lq.zw+rand_frame.xy);
    noise2 += mix(rc*2, 2, vRadius);

    ret = ret+0.5*lum(cross((1-ret),(noise2)))*vec3(0.6,0.5,0.4);
    ret -= mix(0.0,0.1,vRadius);

    ret +=0.1*tex3d(sampler_noisevol_hq, (p+uTime*0.1)*0.7)*mask;


vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((polar.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*roam_cos.y && ret.x<= q24*roam_sin.x)ret.y -= (noise9).x*.5;
if(ret.y> q22*roam_sin.x && ret.y<= q25*roam_cos.x)ret.z -= (noise9).y*.5;
if(ret.z> q23*roam_cos.x && ret.z<= q26*roam_sin.y)ret.x -= (noise9).z*.5;

  fragColor = ret;
}

